package main

import (
	"encoding/json"
	"fmt"
	"html/template"
	"net/http"
	"strings"
)

type Comment struct {
	ID   int    `json:"id"`
	Text string `json:"text"`
}

var comments []Comment

func main() {
	http.HandleFunc("/", handleRequest)
	http.ListenAndServe(":8080", nil)
}

func handleRequest(w http.ResponseWriter, r *http.Request) {
	// Fetch comments from slice
	comments := []Comment{
		{ID: 1, Text: "This is a <b>bold</b> comment"},
		{ID: 2, Text: "This is an <i>italicized</i> comment"},
	}

	// Render comments in HTML page using template
	t := template.Must(template.New("comments").Parse(`
		<html>
			<head>
				<title>Comments</title>
			</head>
			<body>
				{{range .}}
					<div class="comment">
						<p>{{.Text}}</p>
					</div>
				{{end}}
			</body>
		</html>`))

	err := t.Execute(w, comments)
	if err != nil {
		http.Error(w, err.Error(), http.StatusInternalServerError)
	}
}